import asyncio
from collections.abc import Awaitable, Callable


async def run_tasks(
    tasks: list[Callable[[], Awaitable[None]]],
    max_concurrent: int,
) -> None:
    if max_concurrent <= 0:
        raise ValueError("max_concurrent must be positive")

    it = iter(tasks)
    pending: set[asyncio.Task[None]] = set()

    # Seed the initial batch — start up to max_concurrent tasks.
    for _ in range(max_concurrent):
        try:
            t = next(it)
        except StopIteration:
            break
        pending.add(asyncio.create_task(t()))

    try:
        while pending:
            done, pending = await asyncio.wait(
                pending, return_when=asyncio.FIRST_COMPLETED,
            )

            # Re-raise any exception from completed tasks so the caller
            # sees failures from the tasks it asked us to run.
            for d in done:
                d.result()

            # Replenish — start a new task for each slot that opened up.
            for _ in range(len(done)):
                try:
                    t = next(it)
                except StopIteration:
                    break
                pending.add(asyncio.create_task(t()))

    except asyncio.CancelledError:
        # Cancellation (e.g. SIGINT via asyncio.run) delivered while we
        # were waiting.  Do NOT start any queued tasks, but do let any
        # tasks that have already started finish their cleanup (finally
        # blocks etc.) before re-raising the cancellation.
        if pending:
            await asyncio.gather(*pending, return_exceptions=True)
        raise
